import React, { useState } from "react";

const categoryColors = {
  Languages: "var(--accent)",
  Frameworks: "var(--accent2)",
  Tools: "var(--accent3)",
  Databases: "#34d399",
  Concepts: "#f472b6",
};

export function SectionLabel({ text }) {
  return (
    <div style={{ display:"inline-flex", alignItems:"center", gap:8, marginBottom:"0.75rem" }}>
      <span style={{ width:22, height:1, background:"var(--accent)", flexShrink:0 }} />
      <span style={{ fontSize:"0.7rem", color:"var(--accent)", fontFamily:"var(--font-display)", fontWeight:700, letterSpacing:"0.12em", textTransform:"uppercase" }}>{text}</span>
    </div>
  );
}

export const sectionTitle = {
  fontFamily: "var(--font-display)",
  fontWeight: 800,
  fontSize: "clamp(1.6rem, 3.5vw, 2.5rem)",
  letterSpacing: "-0.02em",
  marginBottom: "1.75rem",
  lineHeight: 1.1,
};

export default function Skills({ skills }) {
  const [active, setActive] = useState("Languages");
  const categories = Object.keys(skills);

  return (
    <>
      <style>{`
        .skills-section {
          padding: clamp(2.5rem, 6vw, 5rem) clamp(1.25rem, 5vw, 4rem);
        }
        .skill-tabs {
          display: flex;
          gap: 0.5rem;
          flex-wrap: wrap;
          margin-bottom: 1.5rem;
        }
        .skill-tab {
          padding: 7px 16px;
          border-radius: 99px;
          border: 1px solid;
          font-family: var(--font-display);
          font-weight: 600;
          font-size: clamp(0.72rem, 1.1vw, 0.85rem);
          cursor: pointer;
          transition: all 0.2s;
          white-space: nowrap;
        }
        .skill-chips {
          display: flex;
          flex-wrap: wrap;
          gap: 0.65rem;
        }
        .skill-chip {
          background: var(--surface2);
          border-radius: 6px;
          padding: 9px 15px;
          font-weight: 500;
          font-size: clamp(0.78rem, 1.3vw, 0.9rem);
          color: var(--text);
          transition: border-color 0.2s, background 0.2s;
          cursor: default;
        }
        @media (max-width: 480px) {
          .skill-tab { font-size: 0.72rem; padding: 6px 12px; }
          .skill-chip { font-size: 0.8rem; padding: 8px 12px; }
        }
      `}</style>

      <section className="skills-section" id="skills">
        <SectionLabel text="Expertise" />
        <h2 style={sectionTitle}>Technical Skills</h2>

        <div className="skill-tabs">
          {categories.map(cat => (
            <button key={cat} className="skill-tab" onClick={() => setActive(cat)} style={{
              borderColor: active === cat ? categoryColors[cat] : "var(--border)",
              background: active === cat ? `${categoryColors[cat]}18` : "transparent",
              color: active === cat ? categoryColors[cat] : "var(--muted)",
            }}>{cat}</button>
          ))}
        </div>

        <div className="skill-chips">
          {skills[active].map((skill, i) => (
            <div key={i} className="skill-chip"
              style={{ border: `1px solid ${categoryColors[active]}30`, animationDelay: `${i * 0.04}s` }}
              onMouseEnter={e => { e.currentTarget.style.borderColor = categoryColors[active]; e.currentTarget.style.background = `${categoryColors[active]}10`; }}
              onMouseLeave={e => { e.currentTarget.style.borderColor = `${categoryColors[active]}30`; e.currentTarget.style.background = "var(--surface2)"; }}
            >
              <span style={{ color: categoryColors[active], marginRight: 6, fontSize: "0.65rem" }}>▸</span>
              {skill}
            </div>
          ))}
        </div>
      </section>
    </>
  );
}
